import{i as e,r as t,s as n,t as r}from"./app-DN79xprz.js";var i=JSON.parse(`{"path":"/redaction-processing/boxdetector.html","title":"BoxDetector.py Documentation","lang":"en-US","frontmatter":{},"git":{"updatedTime":1774437245000,"contributors":[{"name":"JaguarM","username":"JaguarM","email":"39597011+JaguarM@users.noreply.github.com","commits":1,"url":"https://github.com/JaguarM"}],"changelog":[{"hash":"f7330e85197db34564e6215e1d272b22e506e24e","time":1774437245000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Add redaction detection backend and docs"}]},"filePathRelative":"redaction-processing/boxdetector.md"}`),a={name:`boxdetector.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="boxdetector-py-documentation" tabindex="-1"><a class="header-anchor" href="#boxdetector-py-documentation"><span>BoxDetector.py Documentation</span></a></h1><p>The [BoxDetector.py](file:///c:/Users/yanni/Desktop/EpsteinTool/guesser/logic/BoxDetector.py) script is designed to rapidly process an image in memory, isolate purely black shapes, and extract standard rectangular redaction boxes while gracefully handling overlapping artifacts and non-rectangular shapes.</p><h2 id="core-function" tabindex="-1"><a class="header-anchor" href="#core-function"><span>Core Function</span></a></h2><h3 id="find-redaction-boxes-in-image-image-bytes-file-c-users-yanni-desktop-epsteintool-guesser-logic-boxdetector-py-4-135" tabindex="-1"><a class="header-anchor" href="#find-redaction-boxes-in-image-image-bytes-file-c-users-yanni-desktop-epsteintool-guesser-logic-boxdetector-py-4-135"><span>[find_redaction_boxes_in_image(image_bytes)](file:///c:/Users/yanni/Desktop/EpsteinTool/guesser/logic/BoxDetector.py#4-135)</span></a></h3><p>This is the primary entry point of the script. It consumes an image (provided as raw byte data) and returns a deduplicated list of detected black rectangular boxes.</p><p><strong>Inputs:</strong></p><ul><li><code>image_bytes</code> <em>(bytes)</em>: Raw byte data of an image, typically read directly from a file (e.g., PNG, JPEG).</li></ul><p><strong>Outputs:</strong></p><ul><li><code>final_boxes</code> <em>(list of tuples)</em>: A list containing tuples of [(x, y, width, height)](file:///c:/Users/yanni/Desktop/EpsteinTool/guesser/logic/BoxDetector.py#110-130) representing the coordinates and dimensions of valid redaction boxes.</li><li><code>width</code> <em>(int)</em>: The overall width of the decoded image.</li><li><code>height</code> <em>(int)</em>: The overall height of the decoded image.</li></ul><hr><h2 id="algorithm-pipeline" tabindex="-1"><a class="header-anchor" href="#algorithm-pipeline"><span>Algorithm Pipeline</span></a></h2><h3 id="_1-image-decoding-preprocessing" tabindex="-1"><a class="header-anchor" href="#_1-image-decoding-preprocessing"><span>1. Image Decoding &amp; Preprocessing</span></a></h3><p>The raw image bytes are decoded using OpenCV into a color format (<code>cv2.imdecode(..., cv2.IMREAD_COLOR)</code>). The algorithm conditionally handles images based on their color channels (Grayscale, BGR, or BGRA) and reduces them into a single-channel grayscale matrix. It then applies a highly strict <strong>pure black threshold</strong>, isolating pixels with a grayscale value of <code>&lt; 10</code> effectively converting the image into a boolean mask where <code>True</code> represents pure black.</p><h3 id="_2-run-length-scanline-extraction" tabindex="-1"><a class="header-anchor" href="#_2-run-length-scanline-extraction"><span>2. Run-Length Scanline Extraction</span></a></h3><p>The algorithm scans the boolean mask pixel-row by pixel-row (top to bottom):</p><ul><li>It utilizes <code>numpy.diff</code> to efficiently find the boundary edges (starts and ends) of continuous horizontal &quot;runs&quot; of black pixels.</li><li>Runs shorter than <code>17</code> pixels wide are instantly discarded, assuming redactions are at least 17px wide.</li></ul><h3 id="_3-active-run-tracking-vertical-box-formation" tabindex="-1"><a class="header-anchor" href="#_3-active-run-tracking-vertical-box-formation"><span>3. Active Run Tracking (Vertical Box Formation)</span></a></h3><p>The detector tracks the &quot;survivability&quot; of runs moving vertically row by row using an <code>active_runs</code> dictionary:</p><ul><li>A previous horizontal run &quot;survives&quot; to the next row if it is mostly contained within a run on the current row (allowing a ±2 pixel horizontal drift).</li><li>Histories and core bounding dimensions (<code>core_x</code>, <code>core_ex</code>) are tracked for each active shape, allowing it to capture boxes even if their vertical edges are slightly imperfect.</li><li>When an active run can no longer be matched to the current row, it terminates. If its accumulated height is <code>&gt;= 10</code> pixels, it advances to edge validation.</li></ul><hr><h2 id="edge-case-handling-shape-filtering" tabindex="-1"><a class="header-anchor" href="#edge-case-handling-shape-filtering"><span>Edge-Case Handling &amp; Shape Filtering</span></a></h2><p>To ensure only actual rectangular redaction strips are captured, specific geometric filters are applied:</p><h3 id="tapered-edge-filter-hole-punches" tabindex="-1"><a class="header-anchor" href="#tapered-edge-filter-hole-punches"><span>Tapered Edge Filter (Hole-Punches)</span></a></h3><p>Because scanned document images might include circular hole-punches that are fully black, they can appear as active runs. To exclude these:</p><ul><li>When an active run terminates, the script analyzes the missing pixels along the top and bottom boundaries.</li><li>If both the top and bottom boundaries are &quot;tapered&quot; (missing up to 30% of pixels in the starting and ending bounding rows respectively), the shape is flagged as a circle/ellipse and discarded.</li></ul><h3 id="intersecting-overlapping-boxes-crosses-ladders-t-shapes" tabindex="-1"><a class="header-anchor" href="#intersecting-overlapping-boxes-crosses-ladders-t-shapes"><span>Intersecting &amp; Overlapping Boxes (Crosses, Ladders, T-shapes)</span></a></h3><p>When vertical layout bars intersect horizontal redaction bars, they create a single contiguous black object. The algorithm corrects these merged shapes in the [clean_overlapping_boxes()](file:///c:/Users/yanni/Desktop/EpsteinTool/guesser/logic/BoxDetector.py#110-130) nested function:</p><ul><li>It iterates through all discovered rectangular zones.</li><li>If a taller vertical box (Box A) intersects a significantly wider horizontal box (Box B), and Box B creates a &quot;T-shape&quot; (ending around the same baseline), it modifies the height of the vertical box so it terminates neatly where the horizontal box begins.</li><li>This ensures intersecting redactions are returned as distinct standard rectangles rather than oddly merged geometric blobs.</li></ul><h2 id="constraints-magic-values-summary" tabindex="-1"><a class="header-anchor" href="#constraints-magic-values-summary"><span>Constraints &amp; Magic Values Summary</span></a></h2><ul><li><strong>Minimum Box Width:</strong> <code>17</code> pixels.</li><li><strong>Minimum Box Height:</strong> <code>10</code> pixels.</li><li><strong>Grayscale Threshold:</strong> <code>&lt; 10</code> (Extremely dark/pure black).</li><li><strong>Run horizontal drift tolerance:</strong> <code>2</code> pixels left or right.</li><li><strong>Taper rejection threshold:</strong> Up to <code>30%</code> pixel loss at the boundary edges.</li></ul>`,30)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};